          }

          render() {


            var header = "Loading ..."
            header = ""
            var content = []
            var rightContent = []
            var leftContent = []

            /*
            const options = [
              { value: 'chocolate', label: 'Chocolate' },
              { value: 'strawberry', label: 'Strawberry' },
              { value: 'vanilla', label: 'Vanilla' }
            ]
            */
           const options = [
             {value: '5930', label: 'Khanna, Raman'},
             {value: '1837', label: 'Sharpe, Bradley'},
             {value: '1850', label: 'Wu, Ethel'},
             {value: '3135', label: 'Shoeb, Marwa'},
             {value: '2470', label: 'Schaeffer, Sarah'},
             {value: '1889', label: 'Najafi, Nader'},
             {value: '6276', label: 'Lai, Andy'},
             {value: '6548', label: 'Auerbach, Andrew'}

           ]

           const cardiologyOptions = [
             {value: '6709', label: 'Rounding Team, Cardiology A'},
             {value: '6710', label: 'Rounding Team, Cardiology B'}, 
             {value: '6711', label: 'Rounding Team, Cardiology C'}, 
             {value: '6712', label: 'Rounding Team, Cardiology D'}
           ]


           const timeOptions = [
             {value: '6', label: '6:00 am'},
             {value: '12', label: '12:00 pm'}, 
             {value: '18', label: '6:00 pm'}, 
             {value: '24', label: '12:00 am'}
           ]



           const groupedOptions = [
             {label: 'Faculty', options: options},
             {label: 'Cardiology Team', options: cardiologyOptions}
           ]









           rightContent.push(<div>Send To:</div>)
           rightContent.push(<div style={{marginTop: "5px", display: "block"}}><Select

              isMulti
              name="sendTo"
              options={groupedOptions}
              className="basic-multi-select"
              classNamePrefix="select"
            /></div>)


            rightContent.push(<div style={{marginTop: "15px"}}>Message:</div>)

            rightContent.push(<div style={{marginTop: "5px", display: "block"}}><textarea style={{width: "100%"}} id="message" name="message" rows="5"></textarea></div>)



          leftContent.push(<div>Date To Send:</div>)
          leftContent.push(<div style={{marginTop: "5px", display: "block"}}><Calendar
            onSelect={(date) => console.log(date)}
            selectDateType="multiple"
            slotInfo={false}
          /></div>)

          leftContent.push(<Select isMulti name="time" options={timeOptions} /> )



          content.push(<div style={{display: "flex"}}><div style={{marginRight: "50px"}}>{leftContent}</div><div style={{flex: "50%"}}>{rightContent}</div></div>)

            /*
            const search = this.props.location.search;
            const params = new URLSearchParams(search);
            const programID = params.get('programid');



            for (let x in this.state.results) {

                  //console.log(this.state.results[x])
                  todayDate = "programID: " + programID

                  var type = ""

                  for (let y in this.state.results[x].types) {
                    type += this.state.results[x].types[y] + "   "
                  }

                  var titleHtml = ""
                  titleHtml = <div style={{marginBottom: '10px'}}><u><b>{this.state.results[x].evaluation_title}</b></u> - {this.state.results[x].evaluationID} * {type}</div>
                  var introduction = ""
                  introduction = <div style={{marginLeft: '10px'}}><b>{this.state.results[x].introduction}</b></div>



                  content.push(titleHtml)
                  content.push(introduction)
                  content.push(<div><hr></hr></div>)
                  content.push(<div>&nbsp;</div>)

            }
*/




